// components/fields/Switch.tsx

import React from 'react';
import type {FieldValues} from 'react-hook-form';

// Using your specified import paths
import type {ISwitch, UseFieldLogicElementProps} from '@lmb-it/kitsconcerto-types';
import {InputSwitch} from "../../../../_compat";

/**
 * Renders a switch (toggle) component.
 * Supports displayAs: 'switch' (default) or 'checkbox' (inline checkbox with label).
 */
export const Switch = <T extends FieldValues>({
                                                  element,
                                                  control,
                                                  getValues,
                                                  fieldLogic,
                                              }: UseFieldLogicElementProps<T>) => {

    // 1. The central hook provides all the necessary state and resolved props.
    const {
        field,
        fieldState,
        label,
        isDisabled,
        isRequired,
        helperText,
        attached,
        style: elementStyle,
        slots,
    } = fieldLogic

    const switchElement = element as ISwitch<T>;

    // 2. The component is now only responsible for rendering the UI.
    return (
        <InputSwitch
            // --- Core react-hook-form props ---
            {...field} // Spreads `onChange`, `onBlur`, `value`, `ref`

            id={field.name}
            label={label}
            disabled={isDisabled}
            required={isRequired}
            invalid={fieldState.invalid}
            errors={fieldState.error?.message}
            helperText={helperText}
            attached={attached}
            displayAs={switchElement.displayAs}
            direction={switchElement.direction}
            style={elementStyle?.input}
            containerStyle={elementStyle?.container}
            slots={slots}
            checked={!!field.value}
        />
    );
};

export default Switch;
